<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Sorting Visualizer</title>
    <style>
        body {
            background-color: #121212;
            color: #e0e0e0;
            font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            height: 100vh;
            margin: 0;
            overflow: hidden;
        }

        #bars {
            display: flex;
            align-items: flex-end;
            width: 90%;
            max-width: 800px;
            height: 300px;
            gap: 2px;
            margin-bottom: 30px;
            border-bottom: 2px solid #333;
        }

        .bar {
            flex: 1;
            background-color: #4caf50;
            min-width: 2px;
            transition: background-color 0.1s ease;
        }

        .controls {
            display: flex;
            gap: 10px;
        }

        button {
            padding: 10px 20px;
            font-size: 14px;
            font-weight: 600;
            cursor: pointer;
            background-color: #333;
            color: white;
            border: 1px solid #555;
            border-radius: 4px;
            transition: background-color 0.2s, border-color 0.2s;
        }

        button:hover {
            background-color: #444;
            border-color: #777;
        }

        button:active {
            background-color: #222;
        }

        button:disabled {
            opacity: 0.5;
            cursor: not-allowed;
        }
    </style>
</head>
<body>

    <div id="bars"></div>

    <div class="controls">
        <button id="sort">Sort</button>
        <button id="shuffle">Shuffle</button>
        <button id="reset">Reset</button>
    </div>

    <script>
        (function() {
            let _arr = [];
            let _original = [];
            let i = 0;
            let j = 0;
            let isDone = false;
            let intervalId = null;

            const barsContainer = document.getElementById('bars');

            function render() {
                barsContainer.innerHTML = '';
                if (_arr.length === 0) return;

                const maxVal = Math.max(..._arr);
                const minVal = Math.min(..._arr);
                // Normalize height so even small differences are visible if range is small
                const range = maxVal - minVal || 1;

                _arr.forEach(val => {
                    const bar = document.createElement('div');
                    bar.className = 'bar';
                    // Height proportional to value relative to the max in current array
                    const heightPercent = (val / maxVal) * 100;
                    bar.style.height = `${Math.max(heightPercent, 2)}%`;
                    barsContainer.appendChild(bar);
                });
            }

            function stopAnimation() {
                if (intervalId) {
                    clearInterval(intervalId);
                    intervalId = null;
                }
            }

            // Expose API to window as required
            window.viz = {
                array: () => [..._arr],
                setArray: (a) => {
                    stopAnimation();
                    _arr = [...a];
                    _original = [...a];
                    i = 0;
                    j = 0;
                    isDone = false;
                    render();
                },
                sortStep: () => {
                    if (isDone || _arr.length <= 1) {
                        isDone = true;
                        return true;
                    }

                    // Bubble Sort Step: One comparison and potential swap
                    if (_arr[j] > _arr[j + 1]) {
                        const temp = _arr[j];
                        _arr[j] = _arr[j + 1];
                        _arr[j + 1] = temp;
                        render();
                    }

                    j++;

                    // If end of current pass reached
                    if (j >= _arr.length - 1 - i) {
                        j = 0;
                        i++;
                    }

                    // If entire sort is finished
                    if (i >= _arr.length - 1) {
                        isDone = true;
                    }

                    return isDone;
                },
                sorted: () => {
                    for (let k = 0; k < _arr.length - 1; k++) {
                        if (_arr[k] > _arr[k + 1]) return false;
                    }
                    return true;
                }
            };

            // UI Logic
            const sortBtn = document.getElementById('sort');
            const shuffleBtn = document.getElementById('shuffle');
            const resetBtn = document.getElementById('reset');

            sortBtn.addEventListener('click', () => {
                if (intervalId) return; // Prevent multiple loops

                sortBtn.disabled = true;
                intervalId = setInterval(() => {
                    const finished = window.viz.sortStep();
                    if (finished) {
                        stopAnimation();
                        sortBtn.disabled = false;
                    }
                }, 50);
            });

            shuffleBtn.addEventListener('click', () => {
                stopAnimation();
                sortBtn.disabled = false;
                const newArr = Array.from({ length: 20 }, () => Math.floor(Math.random() * 100) + 5);
                window.viz.setArray(newArr);
            });

            resetBtn.addEventListener('click', () => {
                stopAnimation();
                sortBtn.disabled = false;
                window.viz.setArray(_original);
            });

            // Initial state
            const initialData = Array.from({ length: 20 }, (_, idx) => (20 - idx) * 4);
            window.viz.setArray(initialData);

        })();
    </script>
</body>
</html>
